func findModelByID(models []models.LLMConfig, agentID *string) *models.LLMConfig {
	if agentID == nil {
		// Find default model
		for _, m := range models {
			if m.IsDefault {
				return &m
			}
		}
		return nil
	}
	for _, m := range models {
		if m.ID == *agentID {
			return &m
		}
	}
	return nil
}

func getModelDisplayName(model *models.LLMConfig) string {
	if model == nil {
		return "No Model"
	}
	return model.Name
}

func findAgentDefinitionByID(agentDefs []models.Agent, agentDefinitionID *string) *models.Agent {
	if agentDefinitionID == nil {
		return nil
	}
	for _, ad := range agentDefs {
		if ad.ID == *agentDefinitionID {
			return &ad
		}
	}
	return nil
}

func StatusBadgeClass(status models.TaskStatus) string {
	switch status {
	case models.StatusRunning:
		return "badge-warning"
	case models.StatusCompleted:
		return "badge-success"
	case models.StatusFailed:
		return "badge-error"
	case models.StatusCancelled:
		return "badge-ghost"
	default:
		return "badge-info"
	}
}

func StatusLabel(status models.TaskStatus) string {
	switch status {
	case models.StatusPending:
		return "Queued"
	case models.StatusQueued:
		return "Queued"
	case models.StatusRunning:
		return "In Progress"
	case models.StatusCompleted:
		return "Completed"
	case models.StatusFailed:
		return "Failed"
	case models.StatusCancelled:
		return "Cancelled"
	default:
		return string(status)
	}
}

// StatusLabelForTask returns a display label considering both status and category.
// Backlog tasks with pending status show "Pending" instead of "Queued",
// and scheduled tasks show "Scheduled".
func StatusLabelForTask(status models.TaskStatus, category models.TaskCategory) string {
	if status == models.StatusPending {
		switch category {
		case models.CategoryBacklog:
			return "Pending"
		case models.CategoryScheduled:
			return "Scheduled"
		}
	}
	return StatusLabel(status)
}

func PriorityLabel(p int) string {
	switch p {
	case 1:
		return "Low"
	case 2:
		return "Normal"
	case 3:
		return "High"
	case 4:
		return "Urgent"
	case 0:
		// Legacy priority value - treat as Normal but don't display badge
		return ""
	default:
		return ""
	}
}

